import{_ as e,o as t,c as r,ag as i}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"豫园与城隍庙攻略2026 | iVoyageWiki","description":"上海豫园与城隍庙旅游攻略，涵盖古典园林、美食街和特色购物指南","frontmatter":{"title":"豫园与城隍庙攻略2026 | iVoyageWiki","description":"上海豫园与城隍庙旅游攻略，涵盖古典园林、美食街和特色购物指南"},"headers":[],"relativePath":"destinations/中国/上海/豫园与城隍庙.md","filePath":"destinations/中国/上海/豫园与城隍庙.md","lastUpdated":null}'),o={name:"destinations/中国/上海/豫园与城隍庙.md"};function n(l,a,h,d,s,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="豫园与城隍庙" tabindex="-1">豫园与城隍庙 <a class="header-anchor" href="#豫园与城隍庙" aria-label="Permalink to &quot;豫园与城隍庙&quot;">​</a></h1><h2 id="城市概览" tabindex="-1">城市概览 <a class="header-anchor" href="#城市概览" aria-label="Permalink to &quot;城市概览&quot;">​</a></h2><p>豫园是上海著名的江南古典园林，建于明代，毗邻城隍庙旅游区。城隍庙一带是上海最具特色的传统文化街区。</p><h2 id="行前准备" tabindex="-1">行前准备 <a class="header-anchor" href="#行前准备" aria-label="Permalink to &quot;行前准备&quot;">​</a></h2><p>建议工作日前往游客较少。豫园门票需提前预约，城隍庙区域免费进入。</p><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><p>地铁10号线、14号线豫园站直达。公交多条线路可达。</p><h2 id="必去景点" tabindex="-1">必去景点 <a class="header-anchor" href="#必去景点" aria-label="Permalink to &quot;必去景点&quot;">​</a></h2><p>豫园园林、城隍庙大殿、九曲桥、湖心亭茶楼、上海老街。</p><h2 id="美食推荐" tabindex="-1">美食推荐 <a class="header-anchor" href="#美食推荐" aria-label="Permalink to &quot;美食推荐&quot;">​</a></h2><p>南翔馒头店的小笼包、绿波廊的本帮菜、宁波汤团店的汤圆、五香豆、梨膏糖。</p><h2 id="购物指南" tabindex="-1">购物指南 <a class="header-anchor" href="#购物指南" aria-label="Permalink to &quot;购物指南&quot;">​</a></h2><p>城隍庙小商品市场有各种特色工艺品、珠宝饰品。豫园老街适合购买丝绸、茶叶等伴手礼。</p><h2 id="行程规划" tabindex="-1">行程规划 <a class="header-anchor" href="#行程规划" aria-label="Permalink to &quot;行程规划&quot;">​</a></h2><p>建议上午游览豫园园林，中午在城隍庙美食广场用餐，下午逛老街和九曲桥，傍晚可到外滩散步。</p><h2 id="避坑指南" tabindex="-1">避坑指南 <a class="header-anchor" href="#避坑指南" aria-label="Permalink to &quot;避坑指南&quot;">​</a></h2><p>城隍庙区域旅游纪念品价格虚高，建议多比价。小笼包名店排队时间长，可选择非高峰时段。</p>',17)])])}const u=e(o,[["render",n]]);export{_ as __pageData,u as default};
